export class ProjectStoryList extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private toolbarEl!: HTMLElement;
    private storiesEl!: HTMLElement;
    private itemTemplateEl!: HTMLTemplateElement;
    private formTemplateEl!: HTMLTemplateElement;
    private sectionTemplateEl!: HTMLTemplateElement;
    private newStoryButton!: HTMLButtonElement;
    private loadSequence = 0;
    private readonly log = createComponentLogger('project-story-list');

    static get observedAttributes(): string[] {
        return ['project-id'];
    }

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.toolbarEl = this.shadowRootRef.getElementById('toolbar') as HTMLElement;
        this.storiesEl = this.shadowRootRef.getElementById('stories') as HTMLElement;
        this.itemTemplateEl = this.shadowRootRef.getElementById('item-template') as HTMLTemplateElement;
        this.formTemplateEl = this.shadowRootRef.getElementById('form-template') as HTMLTemplateElement;
        this.sectionTemplateEl = this.shadowRootRef.getElementById('section-template') as HTMLTemplateElement;
        this.newStoryButton = this.shadowRootRef.getElementById('new-story') as HTMLButtonElement;
        this.newStoryButton.addEventListener('click', () => this.openCreateForm());
        void this.loadData();
    }

    attributeChangedCallback(): void {
        if (!this.isConnected || !this.loadingEl) return;
        void this.loadData();
    }

    private async loadData(): Promise<void> {
        const projectId = this.getAttribute('project-id');
        if (projectId !== 'motivation' || !this.loadingEl) return;

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.storiesEl.hidden = true;
        this.toolbarEl.hidden = true;

        try {
            const response = await ProjectsService.fetchMotivationStories();
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.renderStories(response.stories);
        } catch (error) {
            this.log.error('Failed to load stories', error);
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = 'Failed to load stories.';
        }
    }

    private renderStories(stories: ProjectStorySummary[]): void {
        this.storiesEl.replaceChildren(...stories.map((story) => this.buildStoryEntry(story)));
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.toolbarEl.hidden = false;
        this.storiesEl.hidden = false;
    }

    private buildStoryEntry(story: ProjectStorySummary): DocumentFragment {
        const fragment = this.itemTemplateEl.content.cloneNode(true) as DocumentFragment;

        (fragment.querySelector('.item-id') as HTMLElement).textContent =
            story.storyPoints == null ? `Story ${story.id}` : `Story ${story.id} · ${story.storyPoints} pts`;

        const status = fragment.querySelector('.status') as HTMLElement;
        status.className = projectStatusClass(story.status);
        status.textContent = formatProjectStatusLabel(story.status);

        (fragment.querySelector('.item-title') as HTMLElement).textContent = story.title;
        if (story.status === 'in_progress') {
            (fragment.querySelector('.story-item') as HTMLDetailsElement).open = true;
        }

        const copy = fragment.querySelector('.item-copy') as HTMLElement;
        if (story.story) {
            copy.hidden = false;
            copy.textContent = story.story;
        }

        (fragment.querySelector('.item-meta') as HTMLElement).textContent =
            `${story.priority ?? 'No priority'} · ${story.path}`;

        const entry = fragment.querySelector('.story-entry') as HTMLElement;
        const editBtn = fragment.querySelector('.edit-button') as HTMLButtonElement;
        editBtn.addEventListener('click', (ev) => {
            ev.preventDefault();
            void this.openEditForm(story.id, entry);
        });

        return fragment;
    }

    private async openEditForm(id: string, entry: HTMLElement): Promise<void> {
        const errorEl = entry.querySelector('.item-error') as HTMLElement;
        errorEl.hidden = true;
        try {
            const { story } = await ProjectsService.fetchStory(id);
            const form = this.buildForm({
                mode: 'edit',
                initialTitle: story.title,
                initialSections: story.sections,
                onCancel: () => void this.loadData(),
                onSubmit: async (formData) => {
                    const body: PatchStoryBody = {
                        title: formData.title,
                        sections: formData.sections,
                    };
                    await ProjectsService.patchStory(id, body);
                    await this.loadData();
                },
            });
            entry.replaceWith(this.wrapFormAsEntry(form));
        } catch (error) {
            this.log.error('Failed to open edit form', error);
            errorEl.hidden = false;
            errorEl.textContent = (error instanceof Error ? error.stack ?? error.message : String(error));
        }
    }

    private openCreateForm(): void {
        const form = this.buildForm({
            mode: 'create',
            initialTitle: '',
            initialSections: {},
            onCancel: () => void this.loadData(),
            onSubmit: async (formData) => {
                const body: CreateStoryBody = {
                    title: formData.title,
                    sections: formData.sections,
                    backlogLane: formData.lane,
                };
                await ProjectsService.createStory(body);
                await this.loadData();
            },
        });
        this.storiesEl.prepend(this.wrapFormAsEntry(form));
    }

    private wrapFormAsEntry(form: HTMLElement): HTMLElement {
        const li = document.createElement('li');
        li.className = 'story-entry story-entry--editing';
        li.appendChild(form);
        return li;
    }

    private buildForm(opts: {
        mode: 'edit' | 'create';
        initialTitle: string;
        initialSections: Partial<Record<StorySectionKey, string>>;
        onCancel: () => void;
        onSubmit: (data: { title: string; sections: Partial<Record<StorySectionKey, string>>; lane: ScrumboardBacklogLaneId }) => Promise<void>;
    }): HTMLElement {
        const fragment = this.formTemplateEl.content.cloneNode(true) as DocumentFragment;
        const form = fragment.querySelector('.story-form') as HTMLFormElement;
        const titleInput = form.querySelector('input[name=title]') as HTMLInputElement;
        const sectionsContainer = form.querySelector('.sections') as HTMLElement;
        const laneField = form.querySelector('.lane-field') as HTMLElement;
        const laneSelect = form.querySelector('select[name=lane]') as HTMLSelectElement;
        const errorEl = form.querySelector('.form-error') as HTMLElement;

        titleInput.value = opts.initialTitle;
        if (opts.mode === 'create') laneField.hidden = false;

        const textareas = new Map<StorySectionKey, HTMLTextAreaElement>();
        for (const key of STORY_SECTION_KEYS) {
            const sectionFragment = this.sectionTemplateEl.content.cloneNode(true) as DocumentFragment;
            const label = sectionFragment.querySelector('.field-label') as HTMLElement;
            const textarea = sectionFragment.querySelector('textarea') as HTMLTextAreaElement;
            label.textContent = STORY_SECTION_HEADINGS[key];
            textarea.value = opts.initialSections[key] ?? '';
            textareas.set(key, textarea);
            sectionsContainer.appendChild(sectionFragment);
        }

        if (opts.mode === 'create') {
            this.wireDictationAndStructuring(form, titleInput, textareas, errorEl);
        }

        form.querySelector('.cancel-button')!.addEventListener('click', (ev) => {
            ev.preventDefault();
            opts.onCancel();
        });

        form.addEventListener('submit', async (ev) => {
            ev.preventDefault();
            errorEl.hidden = true;
            const submit = form.querySelector('.save-button') as HTMLButtonElement;
            submit.disabled = true;
            try {
                const sections: Partial<Record<StorySectionKey, string>> = {};
                for (const [key, ta] of textareas) {
                    if (opts.mode === 'create') {
                        if (ta.value.trim().length > 0) sections[key] = ta.value;
                    } else {
                        sections[key] = ta.value;
                    }
                }
                await opts.onSubmit({
                    title: titleInput.value.trim(),
                    sections,
                    lane: laneSelect.value as ScrumboardBacklogLaneId,
                });
            } catch (error) {
                this.log.error(`Failed to ${opts.mode} story`, error);
                errorEl.hidden = false;
                errorEl.textContent = (error instanceof Error ? error.stack ?? error.message : String(error));
                submit.disabled = false;
            }
        });

        return form;
    }

    private wireDictationAndStructuring(
        form: HTMLFormElement,
        titleInput: HTMLInputElement,
        textareas: Map<StorySectionKey, HTMLTextAreaElement>,
        errorEl: HTMLElement,
    ): void {
        const notesBlock = form.querySelector('.notes-block') as HTMLDetailsElement;
        const notesHint = form.querySelector('.notes-hint') as HTMLElement;
        const notesTextarea = form.querySelector('textarea[name=notes]') as HTMLTextAreaElement;
        const notesInterim = form.querySelector('.notes-interim') as HTMLElement;
        const structureButton = form.querySelector('.structure-button') as HTMLButtonElement;

        notesBlock.hidden = false;
        notesBlock.open = true;

        const refreshStructureEnabled = (): void => {
            structureButton.disabled = notesTextarea.value.trim().length === 0;
        };
        notesTextarea.addEventListener('input', refreshStructureEnabled);

        // Dictation events bubble up from the inner <speech-dictation> component.
        form.addEventListener(PROJECT_EVENTS.DICTATION_INTERIM, (event: DictationInterimEvent) => {
            this.log.debug('dictation interim received', { length: event.detail.text.length });
            notesInterim.hidden = false;
            notesInterim.textContent = event.detail.text;
        });
        form.addEventListener(PROJECT_EVENTS.DICTATION_FINAL, (event: DictationFinalEvent) => {
            this.log.debug('dictation final received', { length: event.detail.text.length });
            const join = notesTextarea.value.length > 0 && !notesTextarea.value.endsWith(' ') ? ' ' : '';
            notesTextarea.value = notesTextarea.value + join + event.detail.text;
            notesInterim.hidden = true;
            notesInterim.textContent = '';
            refreshStructureEnabled();
        });
        form.addEventListener(PROJECT_EVENTS.DICTATION_ERROR, (event: DictationErrorEvent) => {
            this.log.warn('dictation error reached form', { code: event.detail.code, message: event.detail.message });
            errorEl.hidden = false;
            errorEl.textContent = `Dictation error (${event.detail.code}): ${event.detail.message}`;
        });

        structureButton.addEventListener('click', async (ev) => {
            ev.preventDefault();
            const notes = notesTextarea.value.trim();
            if (notes.length === 0) return;
            this.log.info('structuring rough notes via AI', { notesLength: notes.length });
            structureButton.disabled = true;
            const previousLabel = structureButton.textContent;
            structureButton.textContent = 'Structuring…';
            errorEl.hidden = true;
            try {
                const { draft } = await ProjectsService.draftStoryFromNotes(notes);
                this.log.info('AI draft received', { title: draft.title, sectionKeys: Object.keys(draft.sections) });
                titleInput.value = draft.title;
                for (const key of STORY_SECTION_KEYS) {
                    const ta = textareas.get(key);
                    if (!ta) continue;
                    const value = draft.sections[key];
                    if (typeof value === 'string') ta.value = value;
                }
                notesBlock.open = false;
                notesHint.hidden = false;
            } catch (err) {
                this.log.error('Failed to structure rough notes', err);
                errorEl.hidden = false;
                errorEl.textContent = (err instanceof Error ? err.stack ?? err.message : String(err));
            } finally {
                structureButton.textContent = previousLabel;
                refreshStructureEnabled();
            }
        });
    }
}

// Used internally by the (future) preview toggle — also surfaces in tests as a sanity check
// that `renderMarkdown` is reachable through the same export surface as the editor itself.
export function previewStoryMarkdown(source: string): DocumentFragment {
    return renderMarkdown(source, { baseHeadingLevel: 4 });
}

export function patchBodyFromStory(original: Story, edited: { title: string; sections: Partial<Record<StorySectionKey, string>> }): PatchStoryBody {
    const body: PatchStoryBody = {};
    if (edited.title !== original.title) body.title = edited.title;
    const sectionDiff: Partial<Record<StorySectionKey, string>> = {};
    for (const key of STORY_SECTION_KEYS) {
        const a = original.sections[key];
        const b = edited.sections[key];
        if (a !== b) sectionDiff[key] = b ?? '';
    }
    if (Object.keys(sectionDiff).length > 0) body.sections = sectionDiff;
    return body;
}

if (!customElements.get('project-story-list')) {
    customElements.define('project-story-list', ProjectStoryList);
}
