/**
 * Lean wrapper around the Web Speech API's `SpeechRecognition`. Targets Chromium only — no
 * webkit-prefix fallback. Global type declarations come from `@types/dom-speech-recognition`
 * (referenced via `tsconfig.app.json` "types"), so this file is just the behavior.
 *
 * `processLocally = true` keeps audio on-device. The browser fires an error event (typically
 * `language-not-supported`) if the requested language pack isn't installed and on-device
 * recognition isn't available — surface it via `onerror` and let the UI decide what to say.
 *
 * MDN: https://developer.mozilla.org/en-US/docs/Web/API/SpeechRecognition
 */

import { createComponentLogger } from './component-logger.js';

const log = createComponentLogger('speech-dictation');

export interface SpeechDictationOptions {
    lang?: string;
    oninterim?: (text: string) => void;
    onfinal?: (text: string) => void;
    onerror?: (error: { code: string; message: string }) => void;
    /**
     * Fires whenever the underlying recognition session ends — user stop, error, or browser-
     * driven silence timeout. The component uses this to keep its mic button state synced.
     */
    onend?: () => void;
    /**
     * Notification hook for the brief on-device prep phase (availability check + optional
     * language-pack install). The component renders a loading state while `phase === 'installing'`.
     */
    onstatus?: (status: { phase: 'checking' | 'installing' | 'ready'; lang: string }) => void;
}

/**
 * Promote bare BCP-47 codes (`en`, `nl`) to a region-bearing form Chrome's on-device packs
 * are keyed by (`en-US`, `nl-NL`). Anything already tagged with a region passes through.
 * Falls back to `en-US` when nothing is supplied.
 */
export function normalizeLang(input: string | undefined): string {
    const candidate = (input ?? document.documentElement.lang ?? '').trim();
    if (!candidate) return 'en-US';
    if (candidate.includes('-')) return candidate;
    const defaults: Record<string, string> = {
        en: 'en-US', nl: 'nl-NL', de: 'de-DE', fr: 'fr-FR', es: 'es-ES', it: 'it-IT', pt: 'pt-PT', ja: 'ja-JP',
    };
    return defaults[candidate.toLowerCase()] ?? `${candidate}-US`;
}

export function isSpeechRecognitionSupported(): boolean {
    return typeof SpeechRecognition !== 'undefined';
}

export class SpeechDictation {
    private recognition: SpeechRecognition | null = null;
    private listening = false;

    constructor(private readonly options: SpeechDictationOptions = {}) {}

    get isListening(): boolean { return this.listening; }

    start(): void {
        // start() is fire-and-forget; errors flow through onerror as before.
        void this.startInternal();
    }

    private async startInternal(): Promise<void> {
        if (this.listening) return;
        if (typeof SpeechRecognition === 'undefined') {
            this.options.onerror?.({ code: 'not-supported', message: 'SpeechRecognition unavailable in this browser' });
            return;
        }

        const lang = normalizeLang(this.options.lang);
        const opts = { langs: [lang], processLocally: true };

        // Availability check + optional install. The static methods landed alongside processLocally;
        // older Chromes won't expose them, so we fall through to a plain start() if they're missing.
        if (typeof SpeechRecognition.available === 'function') {
            this.options.onstatus?.({ phase: 'checking', lang });
            try {
                let status = await SpeechRecognition.available(opts);
                log.info('availability check', { lang, status });
                if (status === 'downloadable' || status === 'downloading') {
                    this.options.onstatus?.({ phase: 'installing', lang });
                    log.info('installing on-device language pack', { lang });
                    await SpeechRecognition.install(opts);
                    status = await SpeechRecognition.available(opts);
                    log.info('post-install availability', { lang, status });
                }
                if (status !== 'available') {
                    this.options.onerror?.({ code: 'language-not-supported', message: `On-device pack for "${lang}" is ${status}.` });
                    return;
                }
            } catch (err) {
                log.warn('availability/install failed; attempting start anyway', { message: err instanceof Error ? err.message : String(err) });
            }
        }

        this.options.onstatus?.({ phase: 'ready', lang });

        const recognition = new SpeechRecognition();
        recognition.lang = lang;
        recognition.continuous = true;
        recognition.interimResults = true;
        recognition.processLocally = true;

        recognition.onresult = (event) => {
            for (let i = event.resultIndex; i < event.results.length; i++) {
                const result = event.results[i];
                const transcript = result[0]?.transcript ?? '';
                if (result.isFinal) this.options.onfinal?.(transcript);
                else this.options.oninterim?.(transcript);
            }
        };
        recognition.onerror = (event) => {
            log.warn('recognition error', { code: event.error, message: event.message });
            this.options.onerror?.({ code: event.error, message: event.message ?? event.error });
        };
        recognition.onend = () => {
            log.info('recognition ended');
            this.listening = false;
            this.options.onend?.();
        };

        this.recognition = recognition;
        this.listening = true;
        recognition.start();
        log.info('started', { lang, processLocally: true });
    }

    stop(): void {
        this.recognition?.stop();
    }

    abort(): void {
        this.recognition?.abort();
        this.listening = false;
    }
}
